import{_ as s,o as t,c as a,a2 as i}from"./chunks/framework.D2pTuMig.js";const m=JSON.parse('{"title":"Compte & Audiences","description":"","frontmatter":{"title":"Compte & Audiences"},"headers":[],"relativePath":"docs/fr/faq/account-audiences.md","filePath":"docs/fr/faq/account-audiences.md"}'),o={name:"docs/fr/faq/account-audiences.md"};function r(u,e,n,c,l,d){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="compte-equipe-audiences" tabindex="-1">Compte, Équipe &amp; Audiences <a class="header-anchor" href="#compte-equipe-audiences" aria-label="Permalink to &quot;Compte, Équipe &amp; Audiences&quot;">​</a></h1><details class="details custom-block"><summary>Comment ajouter un nouvel utilisateur ?</summary><p>Rendez-vous dans <strong>Mon Organisation → Équipe</strong> et cliquez sur <code>+ Ajouter un membre</code>. Recommandé : ayez toujours au moins un backup pour assurer la réactivité sous 48h.</p></details><details class="details custom-block"><summary>Comment référencer une nouvelle audience ?</summary><p>Allez dans <strong>Monétisation → Catalogue</strong> et cliquez sur <code>+ Nouvelle audience</code>. Remplissez les fiches avec soin (Marque, Persona, Panier Moyen) — c&#39;est ce qui convaincra les annonceurs.</p><p>→ <a href="/handbook/docs/fr/publishers/audience-setup.html">Guide détaillé : Configuration d&#39;Audience</a></p></details><details class="details custom-block"><summary>Faut-il créer plusieurs comptes si j&#39;ai plusieurs sites ?</summary><p>Non. Vous pouvez gérer autant d&#39;audiences que vous le souhaitez depuis un seul compte getinside. Chaque site peut avoir sa propre fiche audience indépendante.</p></details><details class="details custom-block"><summary>getinside est-il présent à l&#39;international ?</summary><p>Oui, getinside opère dans toute l&#39;Europe. Vous pouvez ajouter vos audiences européennes et recevoir des campagnes ciblées pour ces pays.</p></details><details class="details custom-block"><summary>Comment suivre mes filleuls (affiliation) ?</summary><p>L&#39;état de vos filleuls est visible dans l&#39;onglet <strong>Affiliation</strong>. Vous touchez une commission récurrente de <strong>20%</strong> sur les frais de plateforme générés par leur activité. Vos gains apparaissent dans <strong>Transactions → Revenus</strong> et peuvent être retirés ou réinvestis depuis votre Wallet.</p></details><details class="details custom-block"><summary>Pourquoi mon &quot;Score Distributeur&quot; a baissé ?</summary><p>Le score est recalculé dynamiquement. Causes fréquentes : délai de réponse &gt; 48h, refus de campagnes sans contre-proposition, volumes distribués inférieurs aux engagements, CPM trop élevé vs la concurrence.</p><p>→ <a href="/handbook/docs/fr/publishers/score-distributor.html">Guide complet : Score Distributeur</a></p></details><details class="details custom-block"><summary>Comment rendre ma fiche audience attractive pour les annonceurs ?</summary><p>Les annonceurs parcourent le catalogue comme une place de marché — votre fiche est votre vitrine. Pour maximiser vos chances de recevoir des offres :</p><ul><li><strong>Soignez les visuels :</strong> photos de vos emballages, exemples de colis, captures de vos emails.</li><li><strong>Décrivez précisément votre persona :</strong> âge, catégorie de produit, fréquence d&#39;achat, géolocalisation.</li><li><strong>Renseignez un Panier Moyen (AOV) réaliste :</strong> un chiffre précis rassure plus qu&#39;une fourchette vague.</li><li><strong>Activez plusieurs formats :</strong> un distributeur proposant Insertion Colis + Emailing est plus attractif qu&#39;un monoforme.</li></ul><p>→ <a href="/handbook/docs/fr/publishers/audience-setup.html">Guide complet : Configuration d&#39;Audience</a></p></details><details class="details custom-block"><summary>Peut-on gérer plusieurs sites depuis un seul compte getinside ?</summary><p>Oui. Un seul compte peut héberger autant de fiches audiences que vous avez de sites ou de flux logistiques distincts. Chaque audience est indépendante et peut avoir ses propres tarifs, formats disponibles et périodes d&#39;ouverture.</p></details>',9)])])}const f=s(o,[["render",r]]);export{m as __pageData,f as default};
